 39	 * A discriminated union (`kind`) the renderer (`~/ui/rich-text`) switches on.
 40	 */
 41	export type RichTextRun =
 42	  | { readonly kind: 'text'; readonly value: string }
 43	  | { readonly kind: 'bold'; readonly value: string }
 44	  | { readonly kind: 'link'; readonly text: string; readonly href: string };
