 46	const toRun = (node: RichTextNode, locale: Locale): RichTextRun => {
 47	  switch (node._tag) {
 48	    case 'text':
 49	      return { kind: 'text', value: node.value[locale] };
 50	    case 'bold':
 51	      return { kind: 'bold', value: node.value[locale] };
 52	    case 'link':
 53	      return { kind: 'link', text: node.text[locale], href: node.href };
 54	  }
 55	};
