 7	
 8	/**
 9	 * The `RichText` renderer is the ONLY place page copy becomes markup (the token
10	 * model is closed — text / bold / link — never arbitrary HTML). These render
11	 * tests pin the load-bearing behaviour the FAQ / contact / volunteer migration
12	 * depends on (`prove-it-works`):
13	 *   - a `bold` run renders `<strong class="font-bold">` (matching the old
14	 *     `<span className="font-bold">`),
15	 *   - a `link` run renders an external anchor with the validated href,
16	 *   - a `\n\n` inside a text run renders back as `<br/><br/>` (the legacy
17	 *     paragraph break carried through the token model as data).
18	 */
19	
20	const render = (runs: readonly RichTextRun[]): string =>
21	  renderToStaticMarkup(<RichText runs={runs} />);
22	
23	describe('RichText', () => {
24	  it('renders a plain text run verbatim', () => {
25	    expect(render([{ kind: 'text', value: 'hello world' }])).toBe(
26	      'hello world',
27	    );
28	  });
29	
30	  it('renders a bold run as a bold span', () => {
31	    const html = render([{ kind: 'bold', value: 'BEFORE' }]);
32	    expect(html).toContain('font-bold');
33	    expect(html).toContain('BEFORE');
34	  });
35	
36	  it('renders a link run as an external anchor with its href', () => {
37	    const html = render([
38	      { kind: 'link', text: 'hello@gyccanada.org', href: 'mailto:hello@gyccanada.org' },
39	    ]);
40	    expect(html).toContain('href="mailto:hello@gyccanada.org"');
41	    expect(html).toContain('target="_blank"');
42	    expect(html).toContain('hello@gyccanada.org');
43	  });
44	
45	  it('turns a `\\n\\n` inside a text run into a `<br/><br/>` paragraph break', () => {
46	    const html = render([{ kind: 'text', value: 'first\n\nsecond' }]);
47	    expect(html).toContain('first');
48	    expect(html).toContain('second');
49	    expect(html).toContain('<br/><br/>');
50	    // The literal newline characters do NOT leak into the markup.
51	    expect(html).not.toContain('\n\n');
52	  });
53	
54	  it('renders a full sequence in order', () => {
55	    const html = render([
56	      { kind: 'bold', value: 'BEFORE' },
57	      { kind: 'text', value: ' registering, email ' },
58	      { kind: 'link', text: 'us', href: 'mailto:hello@gyccanada.org' },
59	    ]);
60	    expect(html.indexOf('BEFORE')).toBeLessThan(
61	      html.indexOf('registering'),
62	    );
63	    expect(html.indexOf('registering')).toBeLessThan(html.indexOf('mailto'));
64	  });
65	});

